// TestIntakeBlockedCarriesRuleFingerprint asserts every intake.blocked entry
// emitted by readiness has a non-empty rule_fingerprint stable across reruns
// with identical inputs.
func TestIntakeBlockedCarriesRuleFingerprint(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatal("executor must not run when intake parks the bead")
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: candidate.ID,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "ambiguous_scope",
				Detail:  "ambiguous scope requires human review",
			}, nil
		},
	})
	require.NoError(t, err)

	events, err := inner.Events(candidate.ID)
	require.NoError(t, err)
	var blocked *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "intake.blocked" {
			blocked = &events[i]
			break
		}
	}
	require.NotNil(t, blocked, "blocked intake must append durable evidence")

	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(blocked.Body), &body))
	ruleFP, hasRuleFP := body["rule_fingerprint"]
	assert.True(t, hasRuleFP, "intake.blocked must include rule_fingerprint")
	assert.NotEmpty(t, ruleFP, "rule_fingerprint must not be empty")

	// Verify rule_fingerprint is a string
	ruleFPStr, ok := ruleFP.(string)
	assert.True(t, ok, "rule_fingerprint must be a string")
	assert.NotEmpty(t, ruleFPStr, "rule_fingerprint string must not be empty")
}

// TestIntakeBlockedSetsOperatorOverride asserts operator_override=true on
// entries written when readiness skipped a downgrade because the bead was
// operator-promoted, and false otherwise.
func TestIntakeBlockedSetsOperatorOverride(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatal("executor must not run when intake parks the bead")
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: candidate.ID,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "ambiguous_scope",
				Detail:  "ambiguous scope requires human review",
			}, nil
		},
	})
	require.NoError(t, err)

	events, err := inner.Events(candidate.ID)
	require.NoError(t, err)
	var blocked *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "intake.blocked" {
			blocked = &events[i]
			break
		}
	}
	require.NotNil(t, blocked, "blocked intake must append durable evidence")

	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(blocked.Body), &body))
	opOverride, hasOpOverride := body["operator_override"]
	assert.True(t, hasOpOverride, "intake.blocked must include operator_override")

	// When not operator-promoted, operator_override should be false
	opOverrideBool, ok := opOverride.(bool)
	assert.True(t, ok, "operator_override must be a boolean")
	// Without a prior triaged event, operator_override should be false
	assert.False(t, opOverrideBool, "operator_override must be false when bead was not operator-promoted")
}

// TestIntakeBlockedFingerprintDedupes asserts running readiness twice with
// identical inputs appends the entry only once.
func TestIntakeBlockedFingerprintDedupes(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatal("executor must not run when intake parks the bead")
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// First run - should append intake.blocked
	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: candidate.ID,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "ambiguous_scope",
				Detail:  "ambiguous scope requires human review",
			}, nil
		},
	})
	require.NoError(t, err)

	events1, err := inner.Events(candidate.ID)
	require.NoError(t, err)
	blockedCount1 := 0
	var firstRuleFP string
	for _, ev := range events1 {
		if ev.Kind == "intake.blocked" {
			blockedCount1++
			var body map[string]any
			_ = json.Unmarshal([]byte(ev.Body), &body)
			if fp, ok := body["rule_fingerprint"].(string); ok {
				firstRuleFP = fp
			}
		}
	}
	assert.Equal(t, 1, blockedCount1, "first run should append one intake.blocked event")
	assert.NotEmpty(t, firstRuleFP, "rule_fingerprint should be set in the event")

	// Unclaim to reset for second run
	require.NoError(t, store.Unclaim(candidate.ID))

	// Second run with identical intake result - should NOT append a duplicate
	_, err = worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: candidate.ID,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "ambiguous_scope",
				Detail:  "ambiguous scope requires human review",
			}, nil
		},
	})
	require.NoError(t, err)

	events2, err := inner.Events(candidate.ID)
	require.NoError(t, err)
	blockedCount2 := 0
	var secondRuleFP string
	for _, ev := range events2 {
		if ev.Kind == "intake.blocked" {
			blockedCount2++
			var body map[string]any
			_ = json.Unmarshal([]byte(ev.Body), &body)
			if fp, ok := body["rule_fingerprint"].(string); ok {
				secondRuleFP = fp
			}
		}
	}
	// Should still be 1, not 2, because of deduplication
	assert.Equal(t, 1, blockedCount2, "second run with identical inputs should not append a duplicate intake.blocked event")
	assert.Equal(t, firstRuleFP, secondRuleFP, "rule_fingerprint should be identical across identical reruns")
}

