// false otherwise.
func readinessRuleFingerprintExists(store ExecuteBeadLoopStore, beadID, ruleFP string) (bool, error) {
	if store == nil || beadID == "" || ruleFP == "" {
		return false, nil
	}
	events, err := store.Events(beadID)
	if err != nil {
		return false, err
	}
	for _, ev := range events {
		if ev.Kind != "intake.blocked" && ev.Kind != "pre_claim_intake.blocked" {
			continue
		}
		fields := eventBodyFields(ev.Body)
		if strings.TrimSpace(fields["rule_fingerprint"]) == ruleFP {
			return true, nil
		}
	}
	return false, nil
}

func eventBodyFields(body string) map[string]string {
	fields := map[string]string{}
	if strings.TrimSpace(body) == "" {
		return fields
	}
	var raw map[string]any
	if err := json.Unmarshal([]byte(body), &raw); err != nil {
		return fields
	}
	for k, v := range raw {
		if s, ok := v.(string); ok {
			fields[k] = s
		}
	}
	return fields
}

